-- ═══════════════════════════════════════════════════════════════════
-- SIGEC-ELOS PATCH 002 — Categorias e Documentos EQPI
-- Execute no SQL Editor do Supabase
-- ═══════════════════════════════════════════════════════════════════

-- 1. Catálogo de documentos (os 33 tipos distintos da EQPI)
CREATE TABLE IF NOT EXISTS public.documents_catalog (
  id           INTEGER PRIMARY KEY,
  name         TEXT NOT NULL,
  auto_collect BOOLEAN DEFAULT FALSE,
  active       BOOLEAN DEFAULT TRUE,
  created_at   TIMESTAMPTZ DEFAULT NOW()
);

-- 2. Categorias hierárquicas (pai → filha → neta)
CREATE TABLE IF NOT EXISTS public.categories (
  id          INTEGER PRIMARY KEY,
  name        TEXT NOT NULL,
  parent_id   INTEGER REFERENCES public.categories(id) ON DELETE CASCADE,
  active      BOOLEAN DEFAULT TRUE,
  sort_order  INTEGER DEFAULT 0,
  created_at  TIMESTAMPTZ DEFAULT NOW()
);

-- 3. Vínculo categoria ↔ documento exigido
CREATE TABLE IF NOT EXISTS public.category_documents (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  category_id INTEGER REFERENCES public.categories(id) ON DELETE CASCADE,
  document_id INTEGER REFERENCES public.documents_catalog(id) ON DELETE CASCADE,
  required    BOOLEAN DEFAULT TRUE,
  UNIQUE(category_id, document_id)
);

-- 4. Categorias que o fornecedor selecionou
CREATE TABLE IF NOT EXISTS public.supplier_categories (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  supplier_id UUID REFERENCES public.suppliers(id) ON DELETE CASCADE,
  category_id INTEGER REFERENCES public.categories(id) ON DELETE CASCADE,
  selected_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(supplier_id, category_id)
);

-- RLS
ALTER TABLE public.documents_catalog    ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.categories           ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.category_documents   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.supplier_categories  ENABLE ROW LEVEL SECURITY;

-- Catálogo de categorias/documentos é público (leitura anônima permitida — dados de referência)
-- Necessário porque o fornecedor seleciona categorias ANTES de criar a conta (step 2 do cadastro)
CREATE POLICY "catalog_read"     ON public.documents_catalog  FOR SELECT USING (true);
CREATE POLICY "categories_read"  ON public.categories         FOR SELECT USING (true);
CREATE POLICY "cat_docs_read"    ON public.category_documents FOR SELECT USING (true);
-- Admin pode modificar catálogo
CREATE POLICY "catalog_admin"    ON public.documents_catalog  FOR ALL USING (public.is_admin());
CREATE POLICY "categories_admin" ON public.categories         FOR ALL USING (public.is_admin());
CREATE POLICY "cat_docs_admin"   ON public.category_documents FOR ALL USING (public.is_admin());
-- Fornecedor gerencia suas categorias
CREATE POLICY "sup_cats_own"     ON public.supplier_categories FOR ALL USING (
  public.is_admin() OR EXISTS (SELECT 1 FROM public.suppliers s WHERE s.id = supplier_id AND s.user_id = auth.uid())
);

